<script setup lang="ts">
type Species = 'bunny' | 'cat' | 'puppy' | 'bear' | 'fox' | 'panda' | 'penguin' | 'hamster'
const props = withDefaults(defineProps<{ species?: Species; skin?: string; accessories?: string[]; mood?: number; level?: number; action?: string }>(), { species: 'bunny', skin: 'lavender', accessories: () => [], mood: 80, level: 1, action: '' })
const actionName = computed(() => String(props.action || '').split('-')[0] || 'idle')
const has = (name: string) => props.accessories.includes(name)
</script>
